   180→				rsp.Summary = append(rsp.Summary, summary)
   181→
   182→			case "dashboard.grafana.app/librarypanels":
   183→				summary := &resourcepb.BulkResponse_Summary{}
   184→				summary.Group = dashboard.GROUP
   185→				summary.Resource = dashboard.LIBRARY_PANEL_RESOURCE
   186→				_, err = sess.SQL("SELECT COUNT(*) FROM "+sql.Table("library_element")+
   187→					" WHERE org_id=?", orgId).Get(&summary.Count)
   188→				rsp.Summary = append(rsp.Summary, summary)
   189→
   190→			case "dashboard.grafana.app/dashboards":
   191→				summary := &resourcepb.BulkResponse_Summary{}
   192→				summary.Group = dashboard.GROUP
   193→				summary.Resource = dashboard.DASHBOARD_RESOURCE
   194→				rsp.Summary = append(rsp.Summary, summary)
   195→
   196→				_, err = sess.SQL("SELECT COUNT(*) FROM "+sql.Table("dashboard")+
   197→					" WHERE is_folder=FALSE AND org_id=?", orgId).Get(&summary.Count)
   198→				if err != nil {
